etting]=value;fill.Size=UDim2.new(percent,0,1,0);label.Text=name   .. ": "   .. tostring(math.floor(value)) ;end end);end for i,tabName in ipairs(tabs) do local tabBtn=Instance.new("TextButton");tabBtn.Size=UDim2.new(0,80,0,30);tabBtn.Position=UDim2.new(0,5 + ((i-1) * 85) ,0.5, -15);tabBtn.BackgroundColor3=((i==currentTab) and Color3.fromRGB(0,255,100)) or Color3.fromRGB(50,50,60) ;tabBtn.Text=tabName;tabBtn.TextColor3=((i==currentTab) and Color3.fromRGB(0,0,0)) or Color3.fromRGB(255,255,255) ;tabBtn.TextSize=12;tabBtn.Font=Enum.Font.Gotham;tabBtn.Parent=tabFrame;tabBtn.MouseButton1Click:Connect(function() currentTab=i;for j,btn in ipairs(tabButtons) do btn.BackgroundColor3=((j==i) and Color3.fromRGB(0,255,100)) or Color3.fromRGB(50,50,60) ;btn.TextColor3=((j==i) and Color3.fromRGB(0,0,0)) or Color3.fromRGB(255,255,255) ;end updateContent();end);table.insert(tabButtons,tabBtn);end function updateContent() for _,child in pairs(scrollFrame:GetChildren()) do if (child:IsA("TextButton") or child:IsA("Frame")) then child:Destroy();end end if (currentTab==1) then createCheckbox("🎯 Noclip","noclip");createCheckbox("✈️ Fly","fly");createCheckbox("🦘 Infinite Jump","infiniteJump");createSlider("⚡ WalkSpeed","walkspeed",16,200,16);createSlider("🚀 Jump Power","jumpPower",50,200,50);createSlider("🌍 Gravity","gravity",0,500,196.2);elseif (currentTab==2) then createCheckbox("🎯 Aimbot","aimbot");createCheckbox("👀 Wallhack","wallhack");createCheckbox("🛡️ Godmode","godmode");createCheckbox("💀 Instant Kill","instakill");createCheckbox("🎮 Anti Kick","antikick");elseif (currentTab==3) then createCheckbox("👁️ ESP","esp");createCheckbox("🔦 Wallhack","wallhack");createCheckbox("📦 Chams","chams");createCheckbox("🎨 Name ESP","nameesp");createSlider("🔍 FOV","fov",30,120,70);elseif (currentTab==4) then createCheckbox("🔄 Anti Kick","antikick");createCheckbox("📝 Spoofer","spoofer");createCheckbox("⏱️ Anti AFK","antiafk");createCheckbox("🗑️ Delete Tools","deletetools");createButton("📌 Teleport Menu",Color3.fromRGB(100,100,255),function() print("Teleport menu");end);elseif (currentTab==5) then createButton("💥 Infinite Yield",Color3.fromRGB(255,50,50),function() loadstring(game:HttpGet("https://raw.githubusercontent.com/EdgeIY/infiniteyield/master/source"))();end);createButton("⚡ CMD-X",Color3.fromRGB(255,100,0),function() loadstring(game:HttpGet("https://raw.githubusercontent.com/CMD-X/CMD-X/master/source"))();end);createButton("🔮 Dark Dex",Color3.fromRGB(150,0,255),function() loadstring(game:HttpGet("https://raw.githubusercontent.com/Babyhamsta/RBLX_Scripts/main/Universal/BypassedDarkDexV3.lua"))();end);createButton("🎭 FE Bypass",Color3.fromRGB(0,150,255),function() print("FE Bypass activated");end);end end game:GetService("RunService").Stepped:Connect(function() if (settings.noclip and character) then for _,part in pairs(character:GetDescendants()) do if (part:IsA("BasePart") and part.CanCollide) then part.CanCollide=false;end end end end);local flying=false;local bodyVelocity,bodyGyro;game:GetService("RunService").Heartbeat:Connect(function() if (settings.fly and character and rootPart) then if  not flying then flying=true;bodyVelocity=Instance.new("BodyVelocity");bodyVelocity.Velocity=Vector3.new(0,0,0);bodyVelocity.MaxForce=Vector3.new(4000,4000,4000);bodyVelocity.Parent=rootPart;bodyGyro=Instance.new("BodyGyro");bodyGyro.MaxTorque=Vector3.new(4000,4000,4000);bodyGyro.P=1000;bodyGyro.Parent=rootPart;end local moveDirection=Vector3.new();local input=game:GetService("UserInputService");if input:IsKeyDown(Enum.KeyCode.W) then moveDirection=moveDirection + Vector3.new(0,0, -1) ;end if input:IsKeyDown(Enum.KeyCode.S) then moveDirection=moveDirection + Vector3.new(0,0,1) ;end if input:IsKeyDown(Enum.KeyCode.A) then moveDirection=moveDirection + Vector3.new( -1,0,0) ;end if input:IsKeyDown(Enum.KeyCode.D) then moveDirection=moveDirection + Vector3.new(1,0,0) ;end if input:IsKeyDown(Enum.KeyCode.Space) then moveDirection=moveDirection + Vector3.new(0,1,0) ;end 